import{_ as n,o as t,c as s,ag as i}from"./chunks/framework.BmJvwvJl.js";const g=JSON.parse('{"title":"Campaign 工作流","description":"","frontmatter":{},"headers":[],"relativePath":"workflows/campaign.md","filePath":"workflows/campaign.md"}'),p={name:"workflows/campaign.md"};function e(l,a,r,d,o,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="campaign-工作流" tabindex="-1">Campaign 工作流 <a class="header-anchor" href="#campaign-工作流" aria-label="Permalink to &quot;Campaign 工作流&quot;">​</a></h1><p><strong>一句话：做一个系列的内容，或者规划一个月的更新节奏时，用这个。</strong></p><hr><h2 id="什么时候该用这个" tabindex="-1">什么时候该用这个 <a class="header-anchor" href="#什么时候该用这个" aria-label="Permalink to &quot;什么时候该用这个&quot;">​</a></h2><p>你想做一个系列的内容。</p><p>比如：</p><ul><li>「这个月我要做 AI 效率工具专题」</li><li>「下周我要发三篇连更」</li><li>「我想测试三个不同的角度，看哪个效果更好」</li><li>「这一季的主题是『程序员成长』，我想做 5 篇成一个系列」</li></ul><p>这些时刻的共同点是：<strong>你不是在写一篇，而是在写多篇。</strong></p><p>你需要的不是「怎么写一篇」，而是「怎么管理一个系列」——篇与篇之间怎么串联、整体节奏怎么安排、每一篇的角度怎么差异化。</p><p><strong>Campaign 工作流就是帮你完成这个「系统性创作」的过程。</strong></p><p>它不是帮你写一篇稿子，而是帮你管理一个创作项目。</p><h3 id="适合-campaign-的场景" tabindex="-1">适合 Campaign 的场景 <a class="header-anchor" href="#适合-campaign-的场景" aria-label="Permalink to &quot;适合 Campaign 的场景&quot;">​</a></h3><ul><li>做一个系列的内容（3篇以上）</li><li>规划一个月/一季度的更新节奏</li><li>想测试不同角度，看哪个效果更好</li><li>周计划、月度主题、季度规划</li><li>需要多篇内容互相配合（比如引流款、转化款、品牌款）</li></ul><h3 id="不适合-campaign-的场景" tabindex="-1">不适合 Campaign 的场景 <a class="header-anchor" href="#不适合-campaign-的场景" aria-label="Permalink to &quot;不适合 Campaign 的场景&quot;">​</a></h3><ul><li>临时起意想写一篇 → 用 Quick</li><li>热点来了想快速响应 → 用 Trend</li><li>只有一个想法，没想清楚要做几篇 → 先用 Quick</li></ul><p>简单来说：<strong>当你脑子里有一个「我要做 X 篇」的规划时，那就是 Campaign。</strong></p><hr><h2 id="campaign-和-quick-的区别" tabindex="-1">Campaign 和 Quick 的区别 <a class="header-anchor" href="#campaign-和-quick-的区别" aria-label="Permalink to &quot;Campaign 和 Quick 的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Quick</th><th>Campaign</th></tr></thead><tbody><tr><td>创作规模</td><td>单篇</td><td>多篇（3篇以上）</td></tr><tr><td>管理方式</td><td>一个 run</td><td>一个 campaign + 多个 note</td></tr><tr><td>规划深度</td><td>选题级</td><td>系列级</td></tr><tr><td>适合场景</td><td>临时起意、日常更新</td><td>系统性规划</td></tr><tr><td>复杂度</td><td>低</td><td>中</td></tr><tr><td>典型案例</td><td>突然想写一篇</td><td>做一个「AI 效率工具」系列</td></tr></tbody></table><p>Quick 是一次性创作，Campaign 是系统性创作。</p><hr><h2 id="一个完整的创作故事" tabindex="-1">一个完整的创作故事 <a class="header-anchor" href="#一个完整的创作故事" aria-label="Permalink to &quot;一个完整的创作故事&quot;">​</a></h2><p>让我带你走一遍 Campaign 的完整流程，看看它是怎么管理一个 3 篇系列的。</p><h3 id="第一步-规划" tabindex="-1">第一步：规划 <a class="header-anchor" href="#第一步-规划" aria-label="Permalink to &quot;第一步：规划&quot;">​</a></h3><p>周一的早上，你坐在咖啡店里，想一个问题：二月要做什么内容？</p><p>你有两个选择：</p><ol><li><strong>佛系更新</strong>：想到什么写什么，发一篇是一篇</li><li><strong>系列化运营</strong>：做一个主题，让它产生累积效应</li></ol><p>你选择了第二种。你决定这个月做一个「AI 效率工具」的系列内容，目标是增长粉丝。</p><p>你想发 3 篇，每篇的角度不同：</p><ol><li>第一篇：钩子要强，容易传播——「5个让我效率翻倍的AI神器」</li><li>第二篇：方法要具体，建立专业度——「我是怎么把AI整合进工作流的」</li><li>第三篇：案例或转化承接——「用AI做副业，我的第一个订单是怎么来的」</li></ol><p>你打开 Claude Code，直接说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:plan</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：AI 效率工具</span></span>
<span class="line"><span>目标：增长粉丝</span></span>
<span class="line"><span>篇数：3篇</span></span>
<span class="line"><span>周期：weekly</span></span></code></pre></div><p>AI 没有立刻开始写，而是先跟你确认了几个问题：</p><ul><li>每篇的目标受众有没有细分？</li><li>三篇之间的逻辑关系是什么？（并列 / 递进 / 悬念）</li><li>发布节奏是什么？（连发 / 隔天发 / 一周一篇）</li></ul><p>你回答完之后，AI 说：「好，我帮你创建 Campaign。」</p><h3 id="第二步-生成-proposal" tabindex="-1">第二步：生成 proposal <a class="header-anchor" href="#第二步-生成-proposal" aria-label="Permalink to &quot;第二步：生成 proposal&quot;">​</a></h3><p>AI 读取了你的 brand 配置，生成了 <strong>proposal.md</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Campaign Proposal: AI 效率工具系列</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 背景</span></span>
<span class="line"><span>目标：通过3篇系列内容，建立「AI效率博主」的专业形象，带动粉丝增长</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 目标受众</span></span>
<span class="line"><span>- 程序员群体</span></span>
<span class="line"><span>- 产品经理</span></span>
<span class="line"><span>- 对效率工具有兴趣的职场人士</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 系列结构</span></span>
<span class="line"><span>- 第1篇：认知建立——「5个神器」</span></span>
<span class="line"><span>- 第2篇：方法论——「工作流整合」</span></span>
<span class="line"><span>- 第3篇：转化——「实战案例」</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 预期效果</span></span>
<span class="line"><span>- 第1篇目标：收藏+转发（传播向）</span></span>
<span class="line"><span>- 第2篇目标：评论+关注（建立信任）</span></span>
<span class="line"><span>- 第3篇目标：私信+转化（变现向）</span></span></code></pre></div><p>你看完觉得方向没问题。AI 继续生成了 <strong>brief.md</strong>（campaign 级别的整体方向）和 <strong>tasks.md</strong>（任务清单，3 篇笔记的任务分配）。</p><h3 id="第三步-第一篇-钩子" tabindex="-1">第三步：第一篇：钩子 <a class="header-anchor" href="#第三步-第一篇-钩子" aria-label="Permalink to &quot;第三步：第一篇：钩子&quot;">​</a></h3><p>你说：「先写第一篇 note-01。」</p><p>AI 生成了初稿。你审核后，觉得开头还不够抓人。审核意见：</p><ul><li>开头太长了，应该直接上工具名</li><li>5个工具的介绍可以更简洁，每个人用一句话说清楚</li><li>CTA 可以更明确：「收藏起来慢慢看」</li></ul><p>你说：「帮我改写开头，要更有冲击力。」</p><p>改写完再审核，通过。</p><h3 id="第四步-第二篇-方法论" tabindex="-1">第四步：第二篇：方法论 <a class="header-anchor" href="#第四步-第二篇-方法论" aria-label="Permalink to &quot;第四步：第二篇：方法论&quot;">​</a></h3><p>继续写第二篇 note-02。</p><p>你说：「写第二篇，方法论的角度。」</p><p>AI 生成了初稿。你审核后发现，这篇是方法论，需要更扎实。审核意见：</p><ul><li>工作流的描述可以更具体，最好有一个实际案例</li><li>缺少一个「before vs after」的对比</li><li>中间有一段太干了，可以加一个场景</li></ul><p>你把这些意见告诉 AI，让它改写。改完你觉得 OK，通过。</p><h3 id="第五步-第三篇-转化" tabindex="-1">第五步：第三篇：转化 <a class="header-anchor" href="#第五步-第三篇-转化" aria-label="Permalink to &quot;第五步：第三篇：转化&quot;">​</a></h3><p>继续写第三篇 note-03。</p><p>你说：「写第三篇，转化篇，要放 CTA。」</p><p>AI 生成了初稿。你审核后发现，这篇需要有明确的行动引导。审核意见：</p><ul><li>CTA 可以更强，比如引导私信</li><li>案例部分可以更真实一点</li><li>结尾可以加一个「下期预告」</li></ul><p>改完之后你觉得 OK，通过。</p><h3 id="第六步-发布" tabindex="-1">第六步：发布 <a class="header-anchor" href="#第六步-发布" aria-label="Permalink to &quot;第六步：发布&quot;">​</a></h3><p>三篇都审核完了，现在是「ready」状态。你说：「帮我生成发布包。」</p><p>AI 生成了一套发布包，包含 3 篇笔记的：</p><ul><li>正文</li><li>封面方向（3个不同的风格）</li><li>配图建议（每个配什么图）</li><li>demo.html（3组可以直接截图的演示稿）</li><li>publish-guide.md（3篇的发布 checklist）</li></ul><p>你把整个目录交给运营同事：「按这个包发。」</p><h3 id="第七步-归档" tabindex="-1">第七步：归档 <a class="header-anchor" href="#第七步-归档" aria-label="Permalink to &quot;第七步：归档&quot;">​</a></h3><p>最后，你说：「归档这个 campaign。」</p><p>AI 把整个创作过程归档，并生成了这个 campaign 的复盘：</p><ul><li>选题：AI效率工具系列（3篇）</li><li>proposal 执行情况：完全按计划执行</li><li>每篇的审核意见和改写轮次</li><li>哪些地方做得好、哪些角度测试失败了下次可以改进</li></ul><p>这些经验会沉淀到你的知识库里。下次你再做类似主题的时候，可以直接从知识库里调取：「上次做这个系列，效果不错，这次可以换个角度试试。」</p><hr><h2 id="交互方式" tabindex="-1">交互方式 <a class="header-anchor" href="#交互方式" aria-label="Permalink to &quot;交互方式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/xhs:plan                            # 发起 campaign</span></span>
<span class="line"><span>/xhs:draft note-01                   # 写第一篇</span></span>
<span class="line"><span>/xhs:review note-01                  # 审核第一篇</span></span>
<span class="line"><span>/xhs:rewrite note-01                 # 改写第一篇（如需要）</span></span>
<span class="line"><span>/xhs:draft note-02                   # 写第二篇</span></span>
<span class="line"><span>/xhs:review note-02                  # 审核第二篇</span></span>
<span class="line"><span>/xhs:rewrite note-02                 # 改写第二篇（如需要）</span></span>
<span class="line"><span>/xhs:draft note-03                   # 写第三篇</span></span>
<span class="line"><span>/xhs:review note-03                  # 审核第三篇</span></span>
<span class="line"><span>/xhs:rewrite note-03                 # 改写第三篇（如需要）</span></span>
<span class="line"><span>/xhs:publish                         # 批量发布</span></span>
<span class="line"><span>/xhs:archive                         # 归档，复盘经验</span></span>
<span class="line"><span>/xhs:status                          # 查看 campaign 状态</span></span></code></pre></div><hr><h2 id="campaign-里的层级关系" tabindex="-1">Campaign 里的层级关系 <a class="header-anchor" href="#campaign-里的层级关系" aria-label="Permalink to &quot;Campaign 里的层级关系&quot;">​</a></h2><p>Campaign 跟 Quick 不一样，它是「容器」，里面有层级：</p><table tabindex="0"><thead><tr><th>层级</th><th>文档</th><th>作用</th></tr></thead><tbody><tr><td>Campaign 级</td><td>proposal、brief、tasks</td><td>整体规划、系列结构、任务分配</td></tr><tr><td>Note 级</td><td>draft、review、rewrite</td><td>单篇笔记的创作和审核</td></tr></tbody></table><p>所以 campaign 管理的是「多个 note 怎么串联」，不是「一篇 note 怎么写」。</p><hr><h2 id="状态流转" tabindex="-1">状态流转 <a class="header-anchor" href="#状态流转" aria-label="Permalink to &quot;状态流转&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>initialized → planned → briefing → drafting → reviewing → iterating → ready → archived</span></span></code></pre></div><table tabindex="0"><thead><tr><th>状态</th><th>意味着什么</th></tr></thead><tbody><tr><td><code>initialized</code></td><td>campaign 已创建</td></tr><tr><td><code>planned</code></td><td>proposal 已生成，规划已完成</td></tr><tr><td><code>briefing</code></td><td>campaign brief 和 tasks 正在形成</td></tr><tr><td><code>drafting</code></td><td>至少有一篇 note 进入写作</td></tr><tr><td><code>reviewing</code></td><td>审核中（至少一篇 note 在审核）</td></tr><tr><td><code>iterating</code></td><td>改写中（至少一篇 note 在改写）</td></tr><tr><td><code>ready</code></td><td>所有笔记完成审核，可以发布</td></tr><tr><td><code>archived</code></td><td>campaign 经验已经沉淀</td></tr></tbody></table><hr><h2 id="什么情况下选-campaign-而不是-quick" tabindex="-1">什么情况下选 Campaign 而不是 Quick <a class="header-anchor" href="#什么情况下选-campaign-而不是-quick" aria-label="Permalink to &quot;什么情况下选 Campaign 而不是 Quick&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐工作流</th></tr></thead><tbody><tr><td>突然有个想法想记录</td><td>Quick</td></tr><tr><td>日常更新，没有系列规划</td><td>Quick</td></tr><tr><td>想做一个系列内容（3篇以上）</td><td>Campaign</td></tr><tr><td>想规划一个月的更新</td><td>Campaign</td></tr><tr><td>想测试不同角度</td><td>Campaign</td></tr><tr><td>周计划、月度主题</td><td>Campaign</td></tr></tbody></table><p>简单来说：<strong>如果你脑子里已经有一个「我要做 X 篇」的规划，那就是 Campaign。</strong></p><hr><h2 id="为什么-campaign-值得用" tabindex="-1">为什么 Campaign 值得用 <a class="header-anchor" href="#为什么-campaign-值得用" aria-label="Permalink to &quot;为什么 Campaign 值得用&quot;">​</a></h2><p>很多人觉得「写一篇就够了为什么要搞这么复杂」。</p><p>让我告诉你为什么：</p><h3 id="_1-系列的累积效应-单篇的随机爆" tabindex="-1">1. 系列的累积效应 &gt; 单篇的随机爆 <a class="header-anchor" href="#_1-系列的累积效应-单篇的随机爆" aria-label="Permalink to &quot;1. 系列的累积效应 &gt; 单篇的随机爆&quot;">​</a></h3><p>一篇笔记爆了，然后呢？没有了。</p><p>一个系列做下来，每一篇都在为账号建立资产。读者看完第一篇觉得不错，会关注你等第二篇；看完第二篇觉得专业，会转发给同事；看完第三篇觉得有用，会私信你。</p><p>这就是系列的威力。</p><h3 id="_2-系统性规划让创作更轻松" tabindex="-1">2. 系统性规划让创作更轻松 <a class="header-anchor" href="#_2-系统性规划让创作更轻松" aria-label="Permalink to &quot;2. 系统性规划让创作更轻松&quot;">​</a></h3><p>很多人创作痛苦的根源是「每天都要想今天发什么」。</p><p>Campaign 帮你一次性把一个月的选题想清楚。你只需要在月初规划一次，然后按计划执行就行。</p><h3 id="_3-数据回流让下次更好" tabindex="-1">3. 数据回流让下次更好 <a class="header-anchor" href="#_3-数据回流让下次更好" aria-label="Permalink to &quot;3. 数据回流让下次更好&quot;">​</a></h3><p>Campaign 结束后，所有的创作经验都会沉淀到知识库里。</p><ul><li>哪篇效果最好？为什么？</li><li>哪个角度失败了？为什么？</li><li>受众更喜欢什么样的内容？</li></ul><p>下次再做 Campaign 的时候，你可以直接从知识库里调取这些经验，而不是从零开始。</p><hr><h2 id="campaign-的最佳实践" tabindex="-1">Campaign 的最佳实践 <a class="header-anchor" href="#campaign-的最佳实践" aria-label="Permalink to &quot;Campaign 的最佳实践&quot;">​</a></h2><ol><li><strong>先想清楚系列结构</strong>：是并列、递进还是悬念？</li><li><strong>每篇要有差异化</strong>：不要三篇都是同一个调性</li><li><strong>设置不同的目标</strong>：有的负责传播，有的负责建立信任，有的负责转化</li><li><strong>做好数据追踪</strong>：每篇发布后，记录数据，下 campaign 复盘时用</li><li><strong>及时归档</strong>：每次 campaign 结束后都要归档，这是你最重要的知识资产</li></ol>`,101)])])}const m=n(p,[["render",e]]);export{g as __pageData,m as default};
